import{_ as e}from"./chunks/demo-doc.NIuiqrK9.js";import{c as o,Q as c,j as t,m as i}from"./chunks/framework.ByJJFMw8.js";const f=JSON.parse('{"title":"支持格式","description":"","frontmatter":{},"headers":[],"relativePath":"guide/formats.md","filePath":"guide/formats.md","lastUpdated":1781514603000}'),a={name:"guide/formats.md"};function r(l,d,s,p,n,h){return c(),t("div",null,[...d[0]||(d[0]=[i('<h1 id="支持格式" tabindex="-1">支持格式 <a class="header-anchor" href="#支持格式" aria-label="Permalink to &quot;支持格式&quot;">​</a></h1><div class="doc-kicker">Runtime Truth</div><p class="doc-lead"> 当前版本内置 <strong>152 个扩展名映射</strong>，覆盖 <strong>20 条预览链路</strong>。 这一页不是“计划支持什么”，而是以当前代码里已经注册好的渲染器为准，告诉你项目现在到底能处理哪些格式、分别走哪条渲染链路，以及在真实业务里应该怎么选。 </p><div class="doc-grid"><div class="doc-card"><h3>152 个扩展名映射</h3><p>覆盖 Office、PDF、OFD、Typst、压缩包、邮件、OLB/DRA、CAD、3D 模型、Excalidraw、draw.io、EPUB、UMD、Markdown、图片、音频、代码/文本和视频等常见附件类型。</p></div><div class="doc-card"><h3>按需异步加载</h3><p>OFD、Typst、压缩包、邮件、OLB/DRA、CAD、3D 模型、绘图、PDF、Office、Markdown、代码高亮等渲染器都会拆成独立异步块，命中格式时才加载。</p></div><div class="doc-card"><h3>两条输入路径</h3><p>既可以用 <code>url</code> 直接预览，也可以在业务侧拿到文件后二次包装成 <code>File</code> 再传入。</p></div><div class="doc-card"><h3>以体验边界为准</h3><p>不同格式会走不同解析链路，兼容优先的格式与高保真格式在样式还原上并不完全一样。</p></div></div><h2 id="当前支持矩阵" tabindex="-1">当前支持矩阵 <a class="header-anchor" href="#当前支持矩阵" aria-label="Permalink to &quot;当前支持矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分类</th><th>扩展名</th><th>渲染链路</th><th>当前表现</th><th>更适合的场景</th></tr></thead><tbody><tr><td>Word</td><td><code>docx</code>、<code>docm</code>、<code>dotx</code>、<code>dotm</code></td><td><code>docx-preview</code> + Web Worker</td><td>白色纸张显示在灰色页面底中，支持宽度自适应和长文档视觉分页；默认在 Worker 内完成解析和 HTML 构建，并按页渐进挂载同一份 docx-preview 结果，Worker 超时会回退到 docx-preview 原生主线程渲染，模板/宏格式按只读预览处理</td><td>新生成的 Word 文档、正式公文、Word 模板</td></tr><tr><td>Word</td><td><code>doc</code>、<code>dot</code></td><td><code>msdoc-viewer</code></td><td>使用 Word 风格页面容器，页面居中显示在灰色工作台中，增强 CFB 容错和表格布局</td><td>存量老文档、Word 97-2003 模板、历史附件回溯</td></tr><tr><td>Excel</td><td><code>xlsx</code>、<code>xltx</code></td><td><code>styled-exceljs</code> + <code>e-virt-table</code></td><td>支持虚拟滚动、列宽/行高、合并单元格、常见样式和 workbook drawing 图片；打印按钮按能力隐藏</td><td>大表格预览、报表、Excel 模板</td></tr><tr><td>Excel 兼容格式</td><td><code>xlsm</code>、<code>xlsb</code>、<code>xls</code>、<code>xlt</code>、<code>xltm</code>、<code>csv</code>、<code>ods</code>、<code>fods</code>、<code>numbers</code></td><td><code>styled-exceljs</code> + <code>e-virt-table</code></td><td>统一读取数据、尺寸和可用样式，按浏览器能力渐进还原</td><td>老表格、跨平台导出的表格</td></tr><tr><td>PowerPoint</td><td><code>pptx</code>、<code>pptm</code>、<code>potx</code>、<code>potm</code>、<code>ppsx</code>、<code>ppsm</code></td><td>自定义 PPTX 渲染器</td><td>以页面展示为主，增强组合图形、旋转/翻转、主题背景、图片裁剪和 EMF 矢量图预览</td><td>汇报材料、说明文档、培训课件、演示模板</td></tr><tr><td>PDF</td><td><code>pdf</code></td><td><code>pdfjs-dist</code></td><td>浏览器端 PDF 渲染，同源 URL 默认渐进读取，服务端支持 Range 时自动分片加载，支持缩放工具栏、页侧边栏/目录树侧边栏切换、宽度自适应、完整打印和导出 HTML</td><td>合同、票据、版式稳定文件</td></tr><tr><td>OFD</td><td><code>ofd</code></td><td><code>DLTech21/ofd.js</code> 源码</td><td>使用浏览器端 OFD 解析和页面渲染，避开 npm dist 授权 wasm 分支</td><td>电子发票、公文、国产版式归档材料</td></tr><tr><td>Typst</td><td><code>typ</code>、<code>typst</code></td><td><code>@myriaddreamin/typst.ts</code> 浏览器 WASM 编译</td><td>直接读取 Typst 源文档并输出按页 SVG，支持完整预览、打印和导出 HTML；compiler WASM 仅命中 Typst 时按需加载</td><td>技术报告、论文草稿、工程文档模板</td></tr><tr><td>压缩包</td><td><code>zip</code>、<code>zipx</code>、<code>7z</code>、<code>rar</code>、<code>tar</code>、<code>gz</code>、<code>gzip</code>、<code>tgz</code>、<code>bz2</code>、<code>bzip2</code>、<code>tbz</code>、<code>tbz2</code>、<code>xz</code>、<code>txz</code>、<code>lzma</code>、<code>zst</code>、<code>tzst</code>、<code>cab</code>、<code>ar</code>、<code>cpio</code>、<code>iso</code>、<code>xar</code>、<code>lha</code>、<code>lzh</code>、<code>jar</code>、<code>war</code>、<code>ear</code>、<code>apk</code>、<code>cbz</code>、<code>cbr</code></td><td><code>libarchive.js</code> + WASM Worker</td><td>先读取目录，点击文件后按需解压；内部文件继续复用统一预览器，并支持 IndexedDB 缓存和体积上限</td><td>归档附件、批量交付包、压缩包内文档快速查看</td></tr><tr><td>邮件</td><td><code>eml</code>、<code>msg</code></td><td><code>postal-mime</code> / <code>@kenjiuno/msgreader</code></td><td>展示头信息、HTML/文本正文、附件列表；附件可下载，也可继续在线预览</td><td>邮件归档、客服工单、客户来信附件</td></tr><tr><td>EDA</td><td><code>olb</code>、<code>dra</code></td><td><code>cfb</code> 容器解析 + EDA 结构分析</td><td>优先解析 OrCAD / Allegro 常见 CFB 容器，展示结构树、元件/封装/Padstack 候选、属性、诊断和可读字符串；非 CFB 文件安全退化</td><td>元件库、封装图纸、EDA 文件初筛</td></tr><tr><td>CAD</td><td><code>dwg</code>、<code>dxf</code>、<code>dwf</code>、<code>dwfx</code>、<code>xps</code></td><td><code>@flyfish-dev/cad-viewer</code></td><td>DWG 通过 Worker + LibreDWG WASM 解析；DXF 使用 JS parser；DWF/DWFx/XPS 使用 native <code>dwf-viewer</code> 渲染 W2D/W3D/XPS 图形，并支持 WebGL / WASM fallback</td><td>工程图纸、二维 CAD 附件、AutoCAD 归档文件</td></tr><tr><td>3D 模型</td><td><code>glb</code>、<code>gltf</code>、<code>obj</code>、<code>stl</code>、<code>ply</code>、<code>fbx</code>、<code>dae</code>、<code>3ds</code>、<code>3mf</code>、<code>amf</code>、<code>usd</code>、<code>usda</code>、<code>usdc</code>、<code>usdz</code>、<code>kmz</code>、<code>pcd</code>、<code>wrl</code>、<code>vrml</code>、<code>xyz</code>、<code>vtk</code>、<code>vtp</code>、<code>step</code>、<code>stp</code>、<code>iges</code>、<code>igs</code>、<code>ifc</code>、<code>3dm</code></td><td>Three.js</td><td>WebGL 交互预览，支持轨道控制、适配视图、网格/坐标轴、线框和自动旋转；工程 CAD/BIM 格式会给出转换原因</td><td>设计模型、点云、三维资产、工程模型</td></tr><tr><td>Excalidraw</td><td><code>excalidraw</code></td><td><code>@excalidraw/excalidraw</code></td><td>使用官方 <code>restore</code> 兼容真实公开文件，再通过 <code>exportToSvg</code> 输出只读 SVG 预览</td><td>白板草图、产品沟通图、流程草稿</td></tr><tr><td>draw.io</td><td><code>drawio</code>、<code>dio</code></td><td>diagrams.net <code>GraphViewer</code></td><td>使用官方 viewer 渲染 mxGraphModel / mxfile，不自行解析 draw.io 方言</td><td>流程图、架构图、业务泳道图</td></tr><tr><td>电子书</td><td><code>epub</code></td><td><code>epubjs</code></td><td>解析 EPUB 包、目录和章节资源，使用滚动阅读避免超宽分页白板</td><td>电子书、培训手册、长篇阅读材料</td></tr><tr><td>电子书</td><td><code>umd</code></td><td>UMD 结构解析 + <code>pako</code></td><td>解析老移动电子书的元数据、章节偏移、章节标题和 zlib 压缩正文</td><td>历史小说附件、旧移动阅读文件</td></tr><tr><td>Markdown</td><td><code>md</code>、<code>markdown</code></td><td>Markdown 渲染器</td><td>保留 Markdown 阅读样式，支持明暗主题阅读面</td><td>README、知识文档、开发说明</td></tr><tr><td>图片</td><td><code>gif</code>、<code>jpg</code>、<code>jpeg</code>、<code>bmp</code>、<code>tiff</code>、<code>tif</code>、<code>png</code>、<code>svg</code>、<code>webp</code></td><td>图片渲染器</td><td>原生图片浏览</td><td>图片附件、设计稿、截图、Logo</td></tr><tr><td>代码/文本</td><td><code>txt</code>、<code>json</code>、<code>js</code>、<code>mjs</code>、<code>cjs</code>、<code>css</code>、<code>java</code>、<code>py</code>、<code>html</code>、<code>htm</code>、<code>jsx</code>、<code>ts</code>、<code>tsx</code>、<code>xml</code>、<code>log</code>、<code>vue</code>、<code>yaml</code>、<code>yml</code>、<code>ini</code>、<code>sh</code>、<code>bash</code>、<code>sql</code>、<code>go</code>、<code>rs</code>、<code>php</code>、<code>c</code>、<code>cpp</code>、<code>cc</code>、<code>h</code>、<code>hpp</code>、<code>cs</code>、<code>diff</code></td><td><code>highlight.js</code></td><td>按源码方式展示并轻量高亮，不执行脚本</td><td>配置文件、日志、代码片段、接口响应</td></tr><tr><td>音频</td><td><code>mp3</code>、<code>mpeg</code>、<code>wav</code>、<code>ogg</code>、<code>oga</code>、<code>opus</code>、<code>m4a</code>、<code>aac</code>、<code>flac</code>、<code>weba</code></td><td>浏览器原生 <code>&lt;audio&gt;</code></td><td>使用原生音频控件播放，具体编码支持取决于浏览器</td><td>录音、播客、语音附件、音效素材</td></tr><tr><td>视频</td><td><code>mp4</code></td><td>浏览器原生视频播放器</td><td>原生播放、带控制条</td><td>演示视频、录屏材料</td></tr></tbody></table><h2 id="按类型看体验和边界" tabindex="-1">按类型看体验和边界 <a class="header-anchor" href="#按类型看体验和边界" aria-label="Permalink to &quot;按类型看体验和边界&quot;">​</a></h2><h3 id="word-文档" tabindex="-1">Word 文档 <a class="header-anchor" href="#word-文档" aria-label="Permalink to &quot;Word 文档&quot;">​</a></h3><ul><li><code>docx</code>、<code>docm</code>、<code>dotx</code>、<code>dotm</code> 使用 <code>docx-preview</code>，适合正文、表格、图片和常规版式较多的现代 Word 文档与模板。当前预览层会恢复白色纸张和灰色页面底，并根据可用宽度自动缩放；宏内容只作为只读文档结构预览，不执行宏。</li><li>DOCX 默认通过 Web Worker 运行 <code>docx-preview</code> 的 ZIP/XML 解析和 HTML 构建，主线程按页面分批挂载同一份 docx-preview 结果并处理缩放、打印和导出；遇到严格 CSP、旧浏览器兼容问题或 Worker DOM 兼容边界时，可通过 <code>options.docx.worker: false</code> 回退到 docx-preview 原生主线程渲染，也可以用 <code>options.docx.workerTimeout</code> 调整默认 15000ms 的自动兜底时间。</li><li><code>doc</code>、<code>dot</code> 使用 <code>msdoc-viewer</code>，并额外套用 Word 风格页面容器。构建前会通过包管理器无关的补丁脚本增强 CFB 局部 sector 容错，它不只是“把内容吐出来”，而是尽量保留文档阅读时的页面感。</li><li>Word 打印和导出 HTML 使用独立导出适配器，只带文档页面和必要 Word 样式，不带 Demo 布局、滚动容器和缩放状态，长文档会按完整页序输出。</li><li>如果源文档缺少显式分页，<code>.docx</code> 预览会在浏览器端补一层视觉分页，避免长文档变成一整条没有纸张边界的内容流。</li><li>如果你的业务能控制导出格式，优先推荐 <code>docx</code>；如果你面对的是存量老文档，当前 <code>.doc</code> 已经可以作为正式能力对外说明。</li></ul><div class="doc-shot"><img src="'+e+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">`.doc` 文件现在会显示在灰色工作台中的白色纸张上，页面居中，阅读路径更接近真实 Word 阅读体验。</p></div><h3 id="office-模板格式" tabindex="-1">Office 模板格式 <a class="header-anchor" href="#office-模板格式" aria-label="Permalink to &quot;Office 模板格式&quot;">​</a></h3><ul><li>当前前端已接入可直接复用的模板格式：<code>dot</code>、<code>dotx</code>、<code>dotm</code>、<code>docm</code>、<code>xlt</code>、<code>xltx</code>、<code>xltm</code>、<code>pptm</code>、<code>potx</code>、<code>potm</code>、<code>ppsx</code>、<code>ppsm</code>。</li><li>这些模板格式仍然走对应的 Word、Excel 或 PowerPoint 渲染链路，按只读预览处理，不执行宏，也不把模板写回文件。</li><li>如果业务系统允许控制附件出口，建议优先沉淀为 <code>docx</code>、<code>xlsx</code>、<code>pptx</code>、<code>pdf</code> 或 <code>ofd</code> 这类更稳定的浏览器预览格式。</li></ul><h3 id="表格类文件" tabindex="-1">表格类文件 <a class="header-anchor" href="#表格类文件" aria-label="Permalink to &quot;表格类文件&quot;">​</a></h3><ul><li>表格类文件统一走 <code>styled-exceljs</code> 解析和 <code>e-virt-table</code> 虚拟渲染，适合需要保留表格结构、合并单元格、workbook drawing 图片和视觉层级的场景。</li><li><code>xlsm</code>、<code>xlsb</code>、<code>xls</code>、<code>xlt</code>、<code>xltm</code>、<code>csv</code>、<code>ods</code>、<code>fods</code>、<code>numbers</code> 会读取格式中能表达的数据、尺寸和样式；部分格式本身不包含完整样式时，会按可用信息渐进还原。</li><li>Excel 预览为了兼顾大表格性能采用虚拟表格，DOM 中不会一次性持有完整工作表，因此当前会主动隐藏打印按钮，避免浏览器只打印当前视口或截断内容。</li><li>如果你正在设计业务导出格式，优先选 <code>xlsx</code>；如果你只是需要把历史附件打开看内容，兼容链路已经足够实用。</li></ul><h3 id="演示文稿、pdf、ofd-与-typst" tabindex="-1">演示文稿、PDF、OFD 与 Typst <a class="header-anchor" href="#演示文稿、pdf、ofd-与-typst" aria-label="Permalink to &quot;演示文稿、PDF、OFD 与 Typst&quot;">​</a></h3><ul><li><code>pptx</code> 适合浏览幻灯片内容、做方案回看和日常演示，不需要 Office 本体参与。</li><li>PPTX 渲染器现在会按 DrawingML 的组合图形坐标系处理 <code>chOff/chExt</code>，组合内元素在缩放、旋转、翻转时会更接近 PowerPoint 中的位置关系。</li><li>主题背景支持从 <code>fillStyleLst</code> / <code>bgFillStyleLst</code> 解析纯色、渐变、图片和平铺图案；PPTX 内嵌的 EMF 图片会尽量转换为 SVG 数据图，避免只显示空白占位。</li><li>图片填充会处理 <code>srcRect</code> 裁剪信息，复杂模板里的裁切图、背景图和组合形状更适合作为真实业务样本回归。</li><li><code>pdf</code> 走 <code>pdfjs-dist</code>，通常是版式最稳定的一类文件，适合合同、流程单、正式成品材料。当前 PDF 视图提供顶部缩放工具栏、页码状态、旋转页兼容、可显隐导航窗格、页面/目录树切换和宽度自适应。同源 URL 会默认使用 PDF.js 的 URL 渐进读取；文件服务支持 Range 时会自动分片加载，避免大文件必须整包下载后才出现首屏。</li><li>PDF 的打印与导出 HTML 会通过专属导出适配器逐页生成完整页面，不依赖当前滚动位置、当前可见页或已经渲染的 canvas，也不会被导航窗格、预览容器或全局样式截断，适合正式归档和审批留痕。</li><li><code>ofd</code> 走 <code>DLTech21/ofd.js</code> 仓库源码，用于国产版式文档在线预览。npm dist 当前会在 wasm 解析层返回授权错误，组件改用同仓库的纯 JS 解析/渲染链路，OFD 依赖仍保持按需异步加载。</li><li><code>typ</code> / <code>typst</code> 始终按源文件直接预览，不会自动探测或替换为同名 PDF。组件会在命中 Typst 时按需加载 <code>@myriaddreamin/typst.ts</code> 的浏览器 WASM 编译与 SVG 渲染链路。</li><li>组件会读取 Typst 输出里的页面尺寸元数据，把整文档拆成按页 SVG 预览，打印和导出 HTML 时只输出文档页面，不带 Demo 外壳。compiler WASM 默认使用固定 CDN 地址，也可以通过 <code>options.typst.compilerWasmUrl</code> 指向私有化部署地址。</li><li>Typst 适合技术报告、论文草稿、工程文档模板和需要保留排版语言源文件的场景。如果文档引用本地图片或拆分文件，建议在业务侧先把资源打包进压缩包，保留完整项目结构。</li><li>如果你更在意“展示结果必须完全稳定”，优先考虑 <code>pdf</code> / <code>ofd</code> 这类版式成品；如果你希望保留可编辑源文件和排版语义，Typst 是更轻量的工程文档入口。</li></ul><h3 id="压缩包、邮件与-eda" tabindex="-1">压缩包、邮件与 EDA <a class="header-anchor" href="#压缩包、邮件与-eda" aria-label="Permalink to &quot;压缩包、邮件与 EDA&quot;">​</a></h3><ul><li>压缩包走 <code>libarchive.js</code>，目录读取在 Worker 中完成，只有用户点击内部文件时才按需解压对应条目，避免一次性把大包全量展开到主线程。私有化部署时一般不需要写死 Worker 路径；组件会先尝试当前 viewer base 下的 <code>vendor/libarchive/worker-bundle.js</code>，失败后回退到打包内置 Worker。</li><li>如果手机 WebView、本地临时服务器、MIME 或 CSP 导致 Worker 初始化超时，组件会继续降级到 ZIP/TAR/GZIP 兼容模式，优先保证常见压缩包能打开目录和内部文档。只有静态目录或 CDN 路径特殊时，才需要通过 <code>options.archive.workerUrl</code> / <code>options.archive.wasmUrl</code> 指定路径。</li><li>压缩包内文件会继续复用同一套文件预览器，所以包里的 PDF、Word、Markdown、代码、图片、邮件或嵌套压缩包都能在体积限制内继续打开。</li><li><code>options.archive.cache</code> 默认启用 IndexedDB 缓存，已解压的内部文件再次打开会更快；<code>maxArchiveSize</code> 和 <code>maxEntryPreviewSize</code> 用于限制压缩包和单个条目的内存风险。</li><li>EML 使用 <code>postal-mime</code> 解析 MIME、正文和附件；MSG 使用 <code>@kenjiuno/msgreader</code> 解析 Outlook MSG，附件同样支持下载和在线预览。</li><li>邮件 HTML 正文渲染在 sandbox iframe 中，不执行脚本；如果你接收外部邮件，仍建议在业务层保留病毒扫描和附件白名单策略。</li><li>OLB / DRA 使用 <code>cfb</code> 读取常见复合文档容器，并按 OrCAD Capture 元件库、Allegro drawing / footprint / padstack 的内容习惯做结构树、对象候选、属性和诊断展示。复杂电气规则、封装编辑和几何校核仍应交给 OrCAD / Allegro 等专业工具。</li></ul><h3 id="cad-图纸" tabindex="-1">CAD 图纸 <a class="header-anchor" href="#cad-图纸" aria-label="Permalink to &quot;CAD 图纸&quot;">​</a></h3><ul><li><code>dwg</code> / <code>dxf</code> / <code>dwf</code> / <code>dwfx</code> / <code>xps</code> 走 <code>@flyfish-dev/cad-viewer</code>，DWG/DXF 归一化为 CAD document 后使用 retained WebGL 渲染，浏览器不支持 WebGL 时回退 Canvas2D。</li><li>DWG 通过独立 Worker 加载 LibreDWG WASM，避免初始化和二进制解析阻塞主线程。项目构建会把 <code>libredwg-web.js</code>、<code>libredwg-web.wasm</code>、<code>dwfv-render.wasm</code> 和 <code>dwg-worker.js</code> 复制到 viewer 静态目录下的 <code>wasm/cad/</code>，也可以通过 <code>options.cad.wasmPath</code> / <code>options.cad.workerUrl</code> / <code>options.cad.dwfWasmUrl</code> 指向私有 CDN。</li><li>DWF / DWFx / XPS 使用 <code>dwf-viewer</code> native renderer，支持 DWF 6+ ZIP 容器、WHIP/W2D 2D sheet、W3D/HSF eModel、DWFx/OPC/XPS 页面、嵌入字体、CAD 线宽适配和 WASM raster fallback。</li></ul><h3 id="_3d-模型" tabindex="-1">3D 模型 <a class="header-anchor" href="#_3d-模型" aria-label="Permalink to &quot;3D 模型&quot;">​</a></h3><ul><li>3D 模型统一走 Three.js，组件会根据扩展名按需加载对应 loader，避免普通文档预览被 3D 依赖拖慢。</li><li><code>glb</code> / <code>gltf</code> 是最推荐的 Web 3D 交换格式；<code>obj</code>、<code>stl</code>、<code>ply</code> 适合轻量几何和打印模型；<code>fbx</code>、<code>dae</code>、<code>3ds</code>、<code>3mf</code>、<code>amf</code>、<code>usd</code> / <code>usdz</code>、<code>kmz</code> 适合兼容设计工具导出的历史或工程资产。</li><li><code>pcd</code>、<code>xyz</code>、<code>vtk</code>、<code>vtp</code> 会按点云或几何模型展示，适合扫描、仿真和工程数据的快速浏览。</li><li><code>step</code> / <code>stp</code>、<code>iges</code> / <code>igs</code>、<code>ifc</code>、<code>3dm</code> 已保留入口，但完整解析需要 OpenCascade、web-ifc 或 rhino3dm 这类 WebAssembly 几何内核；组件会展示原因，生产建议在私有服务端转换为 <code>glb</code> / <code>gltf</code>。</li><li>如果 <code>.gltf</code>、<code>.dae</code>、<code>.fbx</code> 依赖同目录贴图、材质或 <code>.bin</code> 文件，使用 <code>url</code> 远程预览时会以原始 URL 的目录作为资源基准继续加载；使用本地单文件上传时，请优先选择 <code>.glb</code> 或把资源内联。</li></ul><h3 id="绘图文件" tabindex="-1">绘图文件 <a class="header-anchor" href="#绘图文件" aria-label="Permalink to &quot;绘图文件&quot;">​</a></h3><ul><li><code>excalidraw</code> 使用官方 <code>@excalidraw/excalidraw</code> 包的 <code>restore</code> 与 <code>exportToSvg</code> 能力，按需加载后输出只读 SVG 预览，不手写 Excalidraw 图元解析器。</li><li><code>drawio</code> 和 <code>dio</code> 使用官方 diagrams.net <code>GraphViewer</code>，由官方 viewer 处理 mxGraphModel / mxfile、主题和图元兼容，组件只负责创建容器和传入 XML。</li><li>draw.io viewer 脚本来自 diagrams.net 官方静态地址，只有命中 <code>.drawio</code> / <code>.dio</code> 时才加载；需要内网私有化时，可以把该官方脚本镜像到自己的静态资源域名再替换加载地址。</li></ul><h3 id="电子书" tabindex="-1">电子书 <a class="header-anchor" href="#电子书" aria-label="Permalink to &quot;电子书&quot;">​</a></h3><ul><li><code>epub</code> 使用 <code>epubjs</code>，由成熟开源库处理 EPUB zip 包、OPF、目录和章节资源。</li><li>EPUB 预览提供目录窗格、上一章/下一章式导航和阅读进度。正文区域使用滚动文档模式，避免部分浏览器在超宽分页 iframe 下出现白板。为了安全，阅读器不会允许书内脚本执行。</li><li><code>umd</code> 是早期移动阅读器常见的电子书封装。当前没有可靠维护的前端 UMD 阅读库，组件按公开文件结构解析文件头、元数据、章节偏移、章节标题和正文数据块，正文 zlib 解压交给 <code>pako</code>。</li><li>UMD 文本正文按 UTF-16LE 解码，保留章节目录和换行；图片/漫画类 UMD 会尽量按图像数据块展示，但复杂混排文件建议用真实样本补充回归。</li><li>Kindle 专有格式、DRM 电子书或业务加密包不在当前内置范围内，建议在接入侧转换为 EPUB、UMD 文本电子书或 PDF 后预览。</li></ul><h3 id="markdown、代码与文本" tabindex="-1">Markdown、代码与文本 <a class="header-anchor" href="#markdown、代码与文本" aria-label="Permalink to &quot;Markdown、代码与文本&quot;">​</a></h3><ul><li><code>md</code> 和 <code>markdown</code> 会按 Markdown 阅读样式展示，适合项目说明、知识文档和内部手册。Markdown 属于预览器自有阅读面，会跟随系统明暗模式切换；PDF、Word、Excel 这类带原始版式的文件则保持独立纸张或表格背景，避免全局主题破坏源文件视觉。</li><li>代码和文本文件会使用 <code>highlight.js</code> 做轻量高亮，按扩展名匹配语言，不命中时会自动退回纯文本。</li><li>这里有一个很重要的边界：<code>html</code> 文件会被当作源码看，而不是在预览器里当网页执行。这是更安全、也更可控的默认策略。</li></ul><h3 id="图片、音频与视频" tabindex="-1">图片、音频与视频 <a class="header-anchor" href="#图片、音频与视频" aria-label="Permalink to &quot;图片、音频与视频&quot;">​</a></h3><ul><li>图片类支持 <code>gif</code>、<code>jpg</code>、<code>jpeg</code>、<code>bmp</code>、<code>tiff</code>、<code>tif</code>、<code>png</code>、<code>svg</code>、<code>webp</code>。</li><li><code>svg</code> 会作为图片来展示，很适合拿来放矢量图标、流程图和品牌素材。</li><li>音频类支持 <code>mp3</code>、<code>mpeg</code>、<code>wav</code>、<code>ogg</code>、<code>oga</code>、<code>opus</code>、<code>m4a</code>、<code>aac</code>、<code>flac</code>、<code>weba</code>，使用浏览器原生播放器；不同浏览器对编码格式的支持会有差异。</li><li>视频当前支持 <code>mp4</code>，使用浏览器原生播放器，适合最常见的演示和录屏场景。</li></ul><h2 id="真实业务里怎么选" tabindex="-1">真实业务里怎么选 <a class="header-anchor" href="#真实业务里怎么选" aria-label="Permalink to &quot;真实业务里怎么选&quot;">​</a></h2><ul><li>你能控制导出格式：优先使用 <code>docx</code>、<code>xlsx</code>、<code>pptx</code>、<code>pdf</code>、<code>ofd</code>、<code>dxf</code>、<code>glb</code> 这类现代或稳定交换格式。</li><li>你要兼容历史附件：<code>.doc</code> 与 <code>xls/xlsm/xlsb/csv/ods</code> 这一组已经有正式链路，但要接受它们与现代格式在样式上的差异。</li><li>你要看日志、配置或代码：直接用代码/文本链路即可，重点是快速打开、检索内容和保持安全。</li><li>你在做品牌、示意图或视觉素材展示：<code>png</code>、<code>svg</code>、<code>webp</code> 这类图片格式会比转成文档更省心。</li><li>你要预览 CAD：优先提供 <code>dwg</code>、<code>dxf</code>、<code>dwf</code> 或 <code>dwfx</code>；DWG 和 DWF native renderer 会按需加载 Worker/WASM，私有化部署时请确认 viewer 静态目录下的 <code>wasm/cad/</code> 静态资源可访问。</li><li>你要预览 3D 模型：优先沉淀 <code>glb</code> / <code>gltf</code>，历史模型再用 OBJ、STL、PLY、FBX、DAE、3DS、3MF、AMF、USD/USDZ、KMZ 等格式接入；STEP、IGES、IFC、3DM 建议先转换。</li><li>你要预览绘图文件：Excalidraw 和 draw.io 都保留源格式入口，前者走官方恢复与导出 SVG，后者走官方 diagrams.net viewer。</li><li>你要预览电子书或音频：EPUB / UMD 优先保留源文件，音频优先选择浏览器兼容最稳定的 MP3 / OGG。</li></ul><h2 id="不支持的格式会怎样" tabindex="-1">不支持的格式会怎样 <a class="header-anchor" href="#不支持的格式会怎样" aria-label="Permalink to &quot;不支持的格式会怎样&quot;">​</a></h2><p>如果文件扩展名没有命中已注册渲染器，组件会显示“不支持当前格式在线预览”的提示，引导用户下载后查看或转换格式。</p><div class="doc-note"> 最稳妥的做法，不是只看这张表，而是把你业务里最关键的那几类真实文件各准备一份样本，走一遍本地 Demo 和接入页联调。这样你拿去对外说明时，底气会更足。 </div>',35)])])}const b=o(a,[["render",r]]);export{f as __pageData,b as default};
